window.RR_STATS = (function(){
  const L = window.RR_LISTINGS;
  return {
    total: L.length,
    apartments: L.filter(l=>l.type==="apartment").length,
    houses: L.filter(l=>l.type==="house").length,
    commercial: L.filter(l=>l.type==="commercial").length,
    short_term: L.filter(l=>l.type==="short_term").length,
    sources: window.RR_SOURCES.length,
    districts: window.RR_DISTRICTS.length
  };
})();
